#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

// Define process structure
typedef struct Process {
 int pid;
 char state;
} Process;

// Define scheduler structure
typedef struct Scheduler {
 Process* readyQueue;
 int readyQueueSize;
 Process* waitingQueue;
 int waitingQueueSize;
} Scheduler;

// Function to execute a process
void executeProcess(Process* process) {
 printf("Executing process %d for 1 second\n", process->pid);
 sleep(1);
}

// Function to add a process to the scheduler
void addProcess(Scheduler* scheduler, Process* process) {
 scheduler->readyQueue = realloc(scheduler->readyQueue, (scheduler->readyQueueSize + 1) * sizeof(Process));
 scheduler->readyQueue[scheduler->readyQueueSize] = *process;
 scheduler->readyQueueSize++;
}

// Function to schedule processes
void schedule(Scheduler* scheduler) {
 while (scheduler->readyQueueSize > 0) {
 Process currentProcess = scheduler->readyQueue[0];
 executeProcess(&currentProcess);
 if (currentProcess.state == 'T') {
 printf("Removing process %d from system\n", currentProcess.pid);
 } else if (currentProcess.state == 'W') {
 scheduler->waitingQueue = realloc(scheduler->waitingQueue, (scheduler->waitingQueueSize + 1) * sizeof(Process));
 scheduler->waitingQueue[scheduler->waitingQueueSize] = currentProcess;
 scheduler->waitingQueueSize++;
 }
 scheduler->readyQueueSize--;
 scheduler->readyQueue = realloc(scheduler->readyQueue, scheduler->readyQueueSize * sizeof(Process));
 }
}

int main() {
 // Create processes
 Process process1 = {1, 'N'};
 Process process2 = {2, 'N'};
 Process process3 = {3, 'N'};

 // Create scheduler
 Scheduler scheduler;
 scheduler.readyQueue = NULL;
 scheduler.readyQueueSize = 0;
 scheduler.waitingQueue = NULL;
 scheduler.waitingQueueSize = 0;

 // Add processes to scheduler
 addProcess(&scheduler, &process1);
 addProcess(&scheduler, &process2);
 addProcess(&scheduler, &process3);

 // Schedule processes
 schedule(&scheduler);

 return 0;
}
